type Result<T> = {
  success: true;
  data: T;
} | {
  success: false;
  error: string;
};

function fetchData(shouldFail: boolean): Result<string> {
  if (shouldFail) {
    return { success: false, error: 'Failed to fetch data' };
  } else {
    return { success: true, data: 'Data retrieved successfully!' };
  }
}

type ExtractData<T> = T extends { success: true; data: infer D } ? D : never;

type ExtractError<T> = T extends { success: false; error: infer E } ? E : never;

// Usage:
type DataType = ExtractData<Result<string>>; // string
type ErrorType = ExtractError<Result<string>>; // string

function handleResult<T>(result: Result<T>) {
  if (result.success) {
    // TypeScript knows this is the success case
    const data: ExtractData<typeof result> = result.data;
    console.log('Success:', data);
  } else {
    // Here, it's the error case
    const error: ExtractError<typeof result> = result.error;
    console.error('Error:', error);
  }
}

class MyMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name}")
        return super().__new__(cls, name, bases, dct)

class MyClass(metaclass=MyMeta):
    pass

obj = MyClass()

def greet(self):
    return f"Hello from {self.__class__.__name__}!"

class AutoGreetMeta(type):
    def __new__(cls, name, bases, dct):
        dct['greet'] = greet
        return super().__new__(cls, name, bases, dct)

class Person(metaclass=AutoGreetMeta):
    pass

p = Person()
print(p.greet())  # Output: Hello from Person!

class MustHaveSpeakMeta(type):
    def __new__(cls, name, bases, dct):
        if 'speak' not in dct:
            raise TypeError(f"Class {name} must define a 'speak' method")
        return super().__new__(cls, name, bases, dct)

class Dog(metaclass=MustHaveSpeakMeta):
    def speak(self):
        return "Woof!"

